SkillConfig = {}
SkillConfig.skills = {}

function SkillConfig:init(config)
    for id, skill in pairs(config) do
        local item = {}
        item.id = tonumber(skill.id)
        item.itemId = tonumber(skill.itemId)
        item.title = tostring(skill.title)
        item.hint = tostring(skill.hint)
        self.skills[id] = item
    end
    self:prepareSkills()
end

function SkillConfig:prepareSkills()
    for id, skill in pairs(self.skills) do
        HostApi.addSkillItem(SkillConfig.newSkillItem(skill))
    end
end

function SkillConfig.newSkillItem(skill)
    local setting = SkillItem.new()
    setting.SkillId = tonumber(skill.id)
    setting.ItemId = tonumber(skill.itemId)
    setting.Title = tostring(skill.title)
    setting.Hint = tostring(skill.hint)
    return setting
end

function SkillConfig:getSkill(itemId)
    for id, skill in pairs(self.skills) do
        if tonumber(skill.itemId) == itemId then
            return skill
        end
    end
    return nil
end

return SkillConfig